const admin = require('firebase-admin');
const serviceAccount = require('./server/firebase-service-account.json');

admin.initializeApp({
  credential: admin.credential.cert(serviceAccount),
});

const db = admin.firestore();

const DEFAULT_EMAILS_SENT = {
  day1: false,
  day3: false,
  day12: false,
  day14: false,
  reactivation: false,
};

async function run() {
  const snapshot = await db.collection('users').get();
  console.log(`Found ${snapshot.size} users`);

  const batch = db.batch();
  let count = 0;

  for (const doc of snapshot.docs) {
    const data = doc.data();
    if (!data.emailsSent) {
      batch.update(doc.ref, { emailsSent: DEFAULT_EMAILS_SENT });
      count++;
    }
  }

  if (count === 0) {
    console.log('All users already have emailsSent. Nothing to do.');
    process.exit(0);
  }

  await batch.commit();
  console.log(`Updated ${count} users with emailsSent field.`);
  process.exit(0);
}

run().catch((err) => {
  console.error('Error:', err);
  process.exit(1);
});

