const admin = require('firebase-admin');
const serviceAccount = require('./server/firebase-service-account.json');

const VALID_FIELDS = ['day1', 'day3', 'day12', 'day14', 'reactivation'];

const [, , uid, field] = process.argv;

if (!uid || !field) {
  console.error('Usage: node update-emails-sent.js <uid> <field>');
  console.error('Valid fields:', VALID_FIELDS.join(', '));
  process.exit(1);
}

if (!VALID_FIELDS.includes(field)) {
  console.error(`Invalid field: "${field}". Valid fields: ${VALID_FIELDS.join(', ')}`);
  process.exit(1);
}

admin.initializeApp({
  credential: admin.credential.cert(serviceAccount),
});

const db = admin.firestore();

async function run() {
  const ref = db.collection('users').doc(uid);
  const doc = await ref.get();

  if (!doc.exists) {
    console.error(`No user found with uid: ${uid}`);
    process.exit(1);
  }

  await ref.update({
    [`emailsSent.${field}`]: true,
  });

  console.log(`Updated emailsSent.${field} = true for user ${uid}`);
  process.exit(0);
}

run().catch((err) => {
  console.error('Error:', err);
  process.exit(1);
});

