require('dotenv').config({ path: './server/.env' });
const admin = require('firebase-admin');
const nodemailer = require('nodemailer');
const fs = require('fs');
const path = require('path');

// ── Firebase ──────────────────────────────────────────────────────────────────
const serviceAccount = require('./server/firebase-service-account.json');
admin.initializeApp({ credential: admin.credential.cert(serviceAccount) });
const db = admin.firestore();

// ── Gmail SMTP ────────────────────────────────────────────────────────────────
const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: {
    user: process.env.EMAIL_USER,   // e.g. hola@gormaran.io
    pass: process.env.EMAIL_PASS,   // Gmail App Password (not your regular password)
  },
});

// ── Email sequence config ─────────────────────────────────────────────────────
// Each entry: the emailsSent field key, days since registration, email metadata
const EMAIL_SEQUENCE = [
  {
    key: 'day1',
    minDays: 1,
    maxDays: null, // no upper limit — catch-up if missed
    subject: '¡Bienvenido a Gormaran! 🎉',
    template: 'day1.html',
  },
  {
    key: 'day3',
    minDays: 3,
    maxDays: null,
    subject: '¿Cómo va todo? Recursos que te pueden interesar',
    template: 'day3.html',
  },
  {
    key: 'day12',
    minDays: 12,
    maxDays: null,
    subject: 'Lleva tu negocio al siguiente nivel 🚀',
    template: 'day12.html',
  },
  {
    key: 'day14',
    minDays: 14,
    maxDays: null,
    subject: '🎁 Oferta especial para ti — solo 48 horas',
    template: 'day14.html',
  },
  {
    key: 'reactivation',
    minDays: 21,
    maxDays: null,
    subject: 'Te echamos de menos 👋',
    template: 'reactivation.html',
  },
];

// ── Helpers ───────────────────────────────────────────────────────────────────

function loadTemplate(templateFile) {
  const filePath = path.join(__dirname, 'email-templates', templateFile);
  return fs.readFileSync(filePath, 'utf8');
}

function renderTemplate(html, variables) {
  return html.replace(/\{\{(\w+)\}\}/g, (_, key) => variables[key] ?? '');
}

function daysSince(timestamp) {
  const createdAt = timestamp?.toDate ? timestamp.toDate() : new Date(timestamp);
  const ms = Date.now() - createdAt.getTime();
  return Math.floor(ms / (1000 * 60 * 60 * 24));
}

async function sendEmail(to, subject, html) {
  await transporter.sendMail({
    from: `"Gormaran AI Growth Hub" <${process.env.EMAIL_USER}>`,
    to,
    subject,
    html,
  });
}

async function markSent(docRef, field) {
  await docRef.update({ [`emailsSent.${field}`]: true });
}

// ── Main ──────────────────────────────────────────────────────────────────────

async function run() {
  console.log('Fetching free users from Firestore...');
  const snapshot = await db.collection('users').where('subscription', '==', 'free').get();
  console.log(`Found ${snapshot.size} free users\n`);

  let totalSent = 0;
  let totalSkipped = 0;

  for (const doc of snapshot.docs) {
    const user = doc.data();
    const uid = user.uid || doc.id;
    const email = user.email;
    const nombre = user.name || user.displayName || 'Usuario';

    if (!email) {
      console.warn(`[SKIP] uid=${uid} — no email address`);
      totalSkipped++;
      continue;
    }

    if (!user.createdAt) {
      console.warn(`[SKIP] uid=${uid} — no createdAt field`);
      totalSkipped++;
      continue;
    }

    const dias = daysSince(user.createdAt);
    const emailsSent = user.emailsSent ?? {};

    console.log(`Processing ${email} (uid=${uid}, días=${dias})`);

    for (const seq of EMAIL_SEQUENCE) {
      // Skip if already sent
      if (emailsSent[seq.key] === true) continue;

      // Skip if not enough days have passed
      if (dias < seq.minDays) continue;

      // Skip if past upper bound (if defined)
      if (seq.maxDays !== null && dias > seq.maxDays) continue;

      try {
        const rawHtml = loadTemplate(seq.template);
        const html = renderTemplate(rawHtml, { nombre, email });

        await sendEmail(email, seq.subject, html);
        await markSent(doc.ref, seq.key);

        console.log(`  ✓ Sent [${seq.key}] to ${email}`);
        totalSent++;
      } catch (err) {
        console.error(`  ✗ Failed [${seq.key}] for ${email}:`, err.message);
      }
    }
  }

  console.log(`\nDone. Sent: ${totalSent} | Skipped users: ${totalSkipped}`);
  process.exit(0);
}

run().catch((err) => {
  console.error('Fatal error:', err);
  process.exit(1);
});

